var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"결국, 다시 돌아오셨군요.","JPN":"結局、お戻りになりましたね。","ENG":"So, you've come back after all.","TWN":"結果，你又回來了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"만남과 이별 모두, 제 의지와는 상관없이 멋대로 정하셨잖습니까.","JPN":"出会いも別れも、私の意志とは関係なく勝手に決めていたではないですか。","ENG":"You chose when to meet and part, regardless of my will.","TWN":"無論是相遇還是離別，你都隨意決定了，不顧我的意願。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 못다한 이야기를 하러 왔을 뿐입니다, 그레이스 경.","JPN":"私は、果たせなかった話をしに来ただけです、グレース卿。","ENG":"I came only to finish what was left unsaid, Dame Grace.","TWN":"我只是來講述未完的故事，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그레이스 경이라… 이상한 말씀을 하시네요.","JPN":"グレース卿……変なことをおっしゃいますね。","ENG":"\\"Dame Grace\\"... Now that's strange to hear.","TWN":"葛瑞絲小姐嗎……說的話真奇怪呢。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 모든 것은 클리파 에너지가 생전의 모습을 본따 만든 허깨비에 불과합니다.","JPN":"私のすべてはクリファエネルギーが生前の姿を真似て作った偽物です。","ENG":"What you see is just a hollow shell, a phantom shaped by Qlipha energy.","TWN":"我的一切不過是逆卡巴拉能量模仿生前樣貌製造的幻影罷了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"귀공께서 보는 것은 그저 악몽에 불과한 것이지요.","JPN":"貴殿が見ているのは、ただの悪夢に過ぎません。","ENG":"What stands before you is only a nightmare.","TWN":"你所看到的不過是惡夢罷了。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……생각해보면 단순한 이야기였습니다.","JPN":"……考えてみれば、単純な話でした。","ENG":"...Looking back, it was a simple story.","TWN":"……仔細想想，這只是個簡單的故事。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"경께서 말씀하신 악몽의 계기는 늘상 같았고, 그 악몽이 보여주는 것 또한 동일했죠.","JPN":"卿がおっしゃっていた悪夢のきっかけはいつも同じで、その悪夢が見せてくれることもまた同じでした。","ENG":"The nightmare you spoke of always began the same way and showed the same things.","TWN":"你所說的惡夢的起因總是相同，而惡夢所展示的內容也一樣。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"처음 당신을 만난 계기도 어렴풋이 남아있던 힘을 깨우친 순간이었습니다.","JPN":"初めてあなたと出会ったきっかけも、微かに残っていた力に気づいた瞬間でした。","ENG":"Even the first time we met, it was the moment I awakened that faint trace of power.","TWN":"第一次遇見你，也是我隱約喚醒力量的時刻。"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CASTLE_03","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신은 악몽 따위가 아니에요.","JPN":"あなたは悪夢なんかではありません。","ENG":"You're no nightmare.","TWN":"你不是惡夢之類的東西。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"지금껏 제 자신을 몇 번이나 지켜 준… 별의 가호.","JPN":"今まで私自身を何度も守ってくれた……星の加護。","ENG":"You've protected me countless times... You're the Blessing of the Stars.","TWN":"至今為止多次守護我的……星星的守護。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그 안에 담겨있던, 제가 되찾고자 한 정의입니다.","JPN":"その中に込められていた、私が取り戻そうとしていた正義です。","ENG":"And within that, the justice I've sought to reclaim.","TWN":"那裡面包含著我想要找回的正義。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……정의라.","JPN":"……正義ですか。","ENG":"...Justice, is it?","TWN":"……正義嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"세계를 멸망시키려 한 마왕의 동료에게는 어울리지 않는 말이군요.","JPN":"世界を滅亡させようとしていた魔王の仲間には相応しくない言葉ですね。","ENG":"Hardly fitting for someone who once sided with a Demon Lord bent on destruction.","TWN":"這話可不適合想要毀滅世界的魔王的同夥呢。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"예. 어울리지 않습니다.","JPN":"はい。相応しくありません。","ENG":"That's right. It isn't fitting.","TWN":"是的，不合適。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그러니 도망치지 마세요, 그레이스 경.","JPN":"だから逃げないでください、グレース卿。","ENG":"That's why you mustn't run, Dame Grace.","TWN":"所以不要逃跑，葛瑞絲小姐。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"도망치는 것이 아닌, 제 나름대로의 속죄입니다.","JPN":"逃げているのではなく、私なりの贖罪なのです。","ENG":"I'm not running. This is my form of atonement.","TWN":"這不是逃避，而是我自己的贖罪方式。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"기연으로 사도가 되는 것은 피했으나 제 근원은 네헤모트와 동일한 세계에서 비롯된 것.","JPN":"奇縁のおかげで使徒になることは避けられたのですが、私の根源はネヘモトと同じ世界から来たもの。","ENG":"Though I avoided becoming an Apostle, my origins lie in the same world as Nehemoth.","TWN":"雖然因機緣避免成為使徒，但我的根源來自與貝赫莫特相同的世界。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"카란티시르는 그것을 알고 있음에 무구에 담긴 클리파로 별빛을 침식시키려는 것이겠으나…….","JPN":"カランティシルはそれを知っているので、武具に宿っているクリファで星の光を侵食させようとしているのでしょうが……","ENG":"Carantisir knows this. That's why he's trying to corrupt the starlight with Qlipha from the Armament...","TWN":"卡蘭堤西爾知道這一點，想用武具中的逆卡巴拉侵蝕星光……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제 스스로 별을 붕괴시킨다면 그 또한 무의미해지겠죠.","JPN":"私自ら星を崩壊させるなら、それもまた無意味になるはず。","ENG":"But if I destroy the star myself, all of that becomes meaningless.","TWN":"如果我自己摧毀了星星，那也將變得毫無意義吧。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};